/// Compute a display string for a schema's `type`, supporting the array form
/// (e.g. `["string", "null"]`) and the OpenAPI `nullable` keyword.
fn schema_type_string(schema: &serde_json::Value) -> Option<String> {
    let mut types: Vec<String> = match schema.get("type") {
        Some(serde_json::Value::String(s)) => vec![s.clone()],
        Some(serde_json::Value::Array(arr)) => arr
            .iter()
            .filter_map(|v| v.as_str())
            .map(|s| s.to_string())
            .collect(),
        _ => Vec::new(),
    };

    // OpenAPI 3.0 `nullable: true` adds "null" to the allowed types.
    if schema.get("nullable").and_then(|v| v.as_bool()) == Some(true)
        && !types.iter().any(|t| t == "null")
    {
        types.push("null".to_string());
    }

    if types.is_empty() {
        None
    } else {
        Some(types.join("|"))
    }
}
