/// Collect possible value suggestions for a property at the given pointer path.
///
/// Navigates to the subschema at `pointer` + `property_name`, then inspects
/// `const`, `enum`, and `type` (including the array form and OpenAPI
/// `nullable`). Suggestions are composed from `allOf`/`anyOf`/`oneOf` branches
/// and deduplicated.
pub fn collect_values(
    root: &serde_json::Value,
    pointer: &[String],
    property_name: &str,
) -> Vec<ValueSuggestion> {
    let mut full_pointer: Vec<String> = pointer.to_vec();
    full_pointer.push(property_name.to_string());

    let Some(subschema) = resolve_subschema_at_pointer(root, &full_pointer) else {
        return vec![];
    };

    let mut suggestions = Vec::new();
    let mut seen: HashSet<String> = HashSet::new();
    collect_values_from(root, subschema, &mut suggestions, &mut seen, 0);
    suggestions
}

/// Recursive worker for [`collect_values`].
///
/// Follows `$ref` and unions suggestions from `allOf`/`anyOf`/`oneOf` branches.
/// `seen` holds dedup keys: the serialized JSON value for enum/const entries,
/// the fixed marker `"bool"` for boolean, and `"null"` for null.
fn collect_values_from(
    root: &serde_json::Value,
    schema: &serde_json::Value,
    suggestions: &mut Vec<ValueSuggestion>,
    seen: &mut HashSet<String>,
    depth: usize,
) {
    if depth > MAX_SCHEMA_DEPTH {
        return;
    }

    let mut visited = HashSet::new();
    let Some(schema) = follow_ref(root, schema, &mut visited) else {
        return;
    };

    // const: an exact required value (exclusive of other constraints).
    if let Some(const_val) = schema.get("const") {
        push_const(suggestions, seen, const_val);
        return;
    }

    // enum: one of a fixed set.
    if let Some(enum_vals) = schema.get("enum").and_then(|v| v.as_array()) {
        for val in enum_vals {
            push_enum(suggestions, seen, val);
        }
        return;
    }

    // type-based suggestions (single string or array form).
    let types = schema_types(schema);
    if types.iter().any(|t| t == "boolean") {
        push_boolean(suggestions, seen);
    }
    let wants_null = types.iter().any(|t| t == "null")
        || schema.get("nullable").and_then(|v| v.as_bool()) == Some(true);
    if wants_null {
        push_null(suggestions, seen);
    }

    // Compose from sibling composition keywords (`not` is excluded).
    for keyword in ["allOf", "anyOf", "oneOf"] {
        if let Some(branches) = schema.get(keyword).and_then(|v| v.as_array()) {
            for branch in branches {
                collect_values_from(root, branch, suggestions, seen, depth + 1);
            }
        }
    }
}

/// Return the `type` entries of a schema as a list, supporting the array form.
fn schema_types(schema: &serde_json::Value) -> Vec<String> {
    match schema.get("type") {
        Some(serde_json::Value::String(s)) => vec![s.clone()],
        Some(serde_json::Value::Array(arr)) => arr
            .iter()
            .filter_map(|v| v.as_str())
            .map(|s| s.to_string())
            .collect(),
        _ => Vec::new(),
    }
}

fn value_dedup_key(val: &serde_json::Value) -> String {
    serde_json::to_string(val).unwrap_or_default()
}

fn push_const(
    suggestions: &mut Vec<ValueSuggestion>,
    seen: &mut HashSet<String>,
    val: &serde_json::Value,
) {
    if seen.insert(value_dedup_key(val)) {
        suggestions.push(ValueSuggestion::Const(val.clone()));
    }
}

fn push_enum(
    suggestions: &mut Vec<ValueSuggestion>,
    seen: &mut HashSet<String>,
    val: &serde_json::Value,
) {
    if seen.insert(value_dedup_key(val)) {
        suggestions.push(ValueSuggestion::Enum(val.clone()));
    }
}

fn push_boolean(suggestions: &mut Vec<ValueSuggestion>, seen: &mut HashSet<String>) {
    if seen.insert("bool".to_string()) {
