fn snippet_for_type(schema_type: Option<&str>) -> &'static str {
    // For nullable/union types like "string|null", derive the placeholder from
    // the first non-null member so the user gets a sensible default.
    let primary = schema_type.and_then(|s| {
        s.split('|').find(|p| *p != "null").or_else(|| s.split('|').next())
    });
    match primary {
        Some("string") => "\"$1\"",
        Some("number") | Some("integer") => "${1:0}",
        Some("boolean") => "${1:false}",
        Some("object") => "{$1}",
        Some("array") => "[$1]",
        Some("null") => "null",
        _ => "$0",
    }
}
