/// Return a snippet placeholder appropriate for the given JSON schema type.
///
/// For nullable/union types such as `"string|null"`, the placeholder is derived
/// from the first non-null member so the editor offers a sensible default.
fn snippet_for_type(schema_type: Option<&str>) -> &'static str {
    let primary = schema_type.and_then(|s| {
        s.split('|')
            .find(|p| *p != "null")
            .or_else(|| s.split('|').next())
    });
    match primary {
        Some("string") => "\"$1\"",
        Some("number") | Some("integer") => "${1:0}",
        Some("boolean") => "${1:false}",
        Some("object") => "{$1}",
        Some("array") => "[$1]",
        Some("null") => "null",
        _ => "$0",
    }
}

