/// Build `CompletionItem` list from schema value suggestions.
///
/// Items are deduplicated by their rendered label so that overlapping branches
/// of a composed schema never produce duplicate suggestions.
fn build_value_items(
    values: &[schema::ValueSuggestion],
    replace_range: Range,
) -> Vec<CompletionItem> {
    let text_edit = |new_text: String| -> Option<CompletionTextEdit> {
