#[test]
fn collect_properties_anyof_merge() {
    let schema = serde_json::json!({
        "anyOf": [
            { "properties": { "mode": { "type": "string" } }, "required": ["mode"] },
            { "properties": { "level": { "type": "integer" } } }
        ]
    });
    let props = collect_properties(&schema, &[]);
    let names: Vec<&str> = props.iter().map(|p| p.name.as_str()).collect();
    assert!(names.contains(&"mode"));
    assert!(names.contains(&"level"));
    assert!(props.iter().find(|p| p.name == "mode").unwrap().required);
}

#[test]
fn collect_properties_oneof_merge() {
    let schema = serde_json::json!({
        "oneOf": [
            { "properties": { "optionA": { "type": "boolean" } } },
            { "properties": { "optionB": { "type": "string" } } }
        ]
    });
    let props = collect_properties(&schema, &[]);
    let names: Vec<&str> = props.iter().map(|p| p.name.as_str()).collect();
    assert!(names.contains(&"optionA"));
    assert!(names.contains(&"optionB"));
}

#[test]
fn collect_properties_composition_dedupes() {
    // The same property name appearing in two branches must appear once.
    let schema = serde_json::json!({
        "allOf": [
            { "properties": { "shared": { "type": "string", "description": "first" } } },
            { "properties": { "shared": { "type": "string", "description": "second" } } }
        ]
    });
    let props = collect_properties(&schema, &[]);
    let count = props.iter().filter(|p| p.name == "shared").count();
    assert_eq!(count, 1);
    // First definition wins.
    assert_eq!(
        props.iter().find(|p| p.name == "shared").unwrap().description,
        Some("first".into())
    );
}

#[test]
fn collect_properties_nullable_type_display() {
    let schema = serde_json::json!({
        "properties": {
            "nickname": { "type": ["string", "null"] },
            "legacy": { "type": "string", "nullable": true }
        }
    });
    let props = collect_properties(&schema, &[]);
    assert_eq!(
        props
            .iter()
            .find(|p| p.name == "nickname")
            .unwrap()
            .schema_type
            .as_deref(),
        Some("string|null")
    );
    assert_eq!(
        props
            .iter()
            .find(|p| p.name == "legacy")
            .unwrap()
            .schema_type
            .as_deref(),
        Some("string|null")
    );
}

