mod common;

use std::time::Duration;

use common::lsp_client::{TestClient, file_uri};

/// Absolute path to the composition test schema.
fn composition_schema_path() -> String {
    format!(
        "{}/tests/fixtures/composition-schema.json",
        env!("CARGO_MANIFEST_DIR")
    )
}

/// A test document URI in the fixtures directory (so relative $schema resolves).
fn doc_uri() -> String {
    file_uri(&format!(
        "{}/tests/fixtures/test-composition-doc.json",
        env!("CARGO_MANIFEST_DIR")
    ))
}

/// Build a JSON document with an absolute $schema pointing to composition-schema.json.
fn doc_with_schema(content: &str) -> String {
    let schema = composition_schema_path();
    if content.is_empty() {
        format!(r#"{{"$schema": "{schema}"}}"#)
    } else {
        format!(r#"{{"$schema": "{schema}", {content}}}"#)
    }
}

/// Open a document and wait for validation to complete (past the debounce window).
async fn open_and_wait(client: &mut TestClient, uri: &str, content: &str) {
    client.did_open(uri, "json", 1, content).await;
    tokio::time::sleep(Duration::from_millis(300)).await;
    // Drain the diagnostics notification.
    client
        .recv_notification("textDocument/publishDiagnostics")
        .await;
}

/// Extract completion item labels from a completion result.
fn labels(result: &serde_json::Value) -> Vec<String> {
    result["items"]
        .as_array()
        .unwrap_or(&vec![])
        .iter()
        .map(|item| item["label"].as_str().unwrap().to_string())
        .collect()
}

/// anyOf branches contribute their properties, merged and deduplicated.
#[tokio::test]
async fn completion_anyof_merges_properties() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_schema(r#""shape": {}"#);
    let uri = doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let inner_brace = content.rfind('{').unwrap();
    let cursor_col = (inner_brace + 1) as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    let names = labels(&result);
    assert!(
        names.contains(&"type".to_string()),
        "expected 'type' in anyOf completions, got: {names:?}"
    );
    assert!(
        names.contains(&"radius".to_string()),
        "expected 'radius' (first branch) in anyOf completions, got: {names:?}"
    );
    assert!(
        names.contains(&"side".to_string()),
        "expected 'side' (second branch) in anyOf completions, got: {names:?}"
    );
    // 'type' appears in both branches but must be suggested only once.
    assert_eq!(
        names.iter().filter(|n| *n == "type").count(),
        1,
        "'type' must not be duplicated across anyOf branches: {names:?}"
    );
}

/// oneOf branches contribute their properties, merged.
#[tokio::test]
async fn completion_oneof_merges_properties() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_schema(r#""transport": {}"#);
    let uri = doc_uri();
