    let names = labels(&result);
    assert!(
        names.contains(&"kind".to_string()),
        "expected 'kind' in oneOf completions, got: {names:?}"
    );
    assert!(
        names.contains(&"url".to_string()),
        "expected 'url' (first branch) in oneOf completions, got: {names:?}"
    );
    assert!(
        names.contains(&"address".to_string()),
        "expected 'address' (second branch) in oneOf completions, got: {names:?}"
    );
}

/// allOf merges a $ref'd definition with locally defined properties.
#[tokio::test]
async fn completion_allof_with_ref_merges_properties() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_schema(r#""database": {}"#);
    let uri = doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let inner_brace = content.rfind('{').unwrap();
    let cursor_col = (inner_brace + 1) as u32;
