/// A nullable type in array form (["boolean", "null"]) yields true, false, null.
#[tokio::test]
async fn completion_nullable_type_array_suggests_null() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_schema(r#""enabled": null"#);
    let uri = doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let idx = content.find("\"enabled\": ").unwrap() + "\"enabled\": ".len();
    let result = client.completion(&uri, 0, idx as u32).await;

    let names = labels(&result);
    assert!(
        names.contains(&"true".to_string()),
        "expected 'true' for nullable boolean, got: {names:?}"
    );
    assert!(
        names.contains(&"false".to_string()),
        "expected 'false' for nullable boolean, got: {names:?}"
    );
    assert!(
        names.contains(&"null".to_string()),
        "expected 'null' from nullable type array, got: {names:?}"
    );
}

/// The OpenAPI `nullable: true` keyword adds null to the value suggestions.
#[tokio::test]
async fn completion_openapi_nullable_suggests_null() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_schema(r#""callback": null"#);
    let uri = doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let idx = content.find("\"callback\": ").unwrap() + "\"callback\": ".len();
    let result = client.completion(&uri, 0, idx as u32).await;

    let names = labels(&result);
    // A plain string type has no concrete value suggestion, so only null remains.
    assert_eq!(
        names,
