    );
}

/// Overlapping enums across anyOf branches are unioned without duplicates.
#[tokio::test]
async fn completion_anyof_enum_values_deduplicated() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_schema(r#""priority": null"#);
    let uri = doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let idx = content.find("\"priority\": ").unwrap() + "\"priority\": ".len();
    let result = client.completion(&uri, 0, idx as u32).await;

    let names = labels(&result);
    // Branches are ["low","normal","high"] and ["normal","urgent"].
    let expected = ["\"low\"", "\"normal\"", "\"high\"", "\"urgent\""];
    for e in expected {
        assert!(
            names.contains(&e.to_string()),
            "expected {e} in priority completions, got: {names:?}"
        );
    }
    assert_eq!(
        names.len(),
        expected.len(),
        "expected no duplicate enum values across anyOf branches, got: {names:?}"
    );
}

/// oneOf of const values produces each const as a distinct suggestion.
#[tokio::test]
async fn completion_oneof_const_values() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_schema(r#""replicas": null"#);
    let uri = doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let idx = content.find("\"replicas\": ").unwrap() + "\"replicas\": ".len();
    let result = client.completion(&uri, 0, idx as u32).await;

    let names = labels(&result);
    assert_eq!(
        names,
        vec!["1".to_string(), "3".to_string(), "5".to_string()],
        "expected all const values from oneOf branches, got: {names:?}"
    );
}

/// Nullable properties surface a readable type in the completion detail.
#[tokio::test]
async fn completion_nullable_property_detail() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_schema("");
    let uri = doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let cursor_col = (content.len() - 1) as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    let items = result["items"].as_array().unwrap();
    let enabled = items.iter().find(|i| i["label"] == "enabled").unwrap();
    let detail = enabled["detail"].as_str().unwrap();
    assert!(
        detail.contains("boolean|null"),
        "expected 'boolean|null' detail for nullable property, got: {detail}"
    );
}

